document.addEventListener("DOMContentLoaded",()=>{if(!CONFIG.path){console.warn("`hexo-generator-searchdb` plugin is not installed!");return}const n=new LocalSearch({path:CONFIG.path,top_n_per_article:CONFIG.localsearch.top_n_per_article,unescape:CONFIG.localsearch.unescape});const r=document.querySelector(".search-input");const i=document.querySelector(".search-result-container");const e=()=>{if(!n.isfetched)return;const e=r.value.trim().toLowerCase();const t=e.split(/[-\s]+/);let s=[];if(e.length>0){s=n.getResultItems(t)}if(t.length===1&&t[0]===""){i.innerHTML='<div class="search-result-icon"><i class="fa fa-search fa-5x"></i></div>'}else if(s.length===0){i.innerHTML='<div class="search-result-icon"><i class="far fa-frown fa-5x"></i></div>'}else{s.sort((e,t)=>{if(e.includedCount!==t.includedCount){return t.includedCount-e.includedCount}else if(e.hitCount!==t.hitCount){return t.hitCount-e.hitCount}return t.id-e.id});const c=CONFIG.i18n.hits.replace("${hits}",s.length);i.innerHTML=`<div class="search-stats">${c}</div>
        <hr>
        <ul class="search-result-list">${s.map(e=>e.item).join("")}</ul>`;if(typeof pjax==="object")pjax.refresh(i)}};n.highlightSearchWords(document.querySelector(".post-body"));if(CONFIG.localsearch.preload){n.fetchData()}r.addEventListener("input",e);window.addEventListener("search:loaded",e);document.querySelectorAll(".popup-trigger").forEach(e=>{e.addEventListener("click",()=>{NexT.utils.setGutter();document.body.classList.add("search-active");setTimeout(()=>r.focus(),500);if(!n.isfetched)n.fetchData()})});const t=()=>{NexT.utils.setGutter("0");document.body.classList.remove("search-active")};document.querySelector(".search-pop-overlay").addEventListener("click",e=>{if(e.target===document.querySelector(".search-pop-overlay")){t()}});document.querySelector(".popup-btn-close").addEventListener("click",t);document.addEventListener("pjax:success",()=>{n.highlightSearchWords(document.querySelector(".post-body"));t()});window.addEventListener("keydown",e=>{if((e.ctrlKey||e.metaKey)&&e.key==="k"){e.preventDefault();NexT.utils.setGutter();document.body.classList.add("search-active");setTimeout(()=>r.focus(),500);if(!n.isfetched)n.fetchData()}});window.addEventListener("keyup",e=>{if(e.key==="Escape"){t()}})});